// Find two numbers in a SORTED array that add up to target
vector<int> numbers = {2, 4, 7, 11, 15};
int target = 15;

for (int i = 0; i < numbers.size(); i++)
{
    for (int j = i + 1; j < numbers.size(); j++) // checks EVERY pair
    {
        if (numbers[i] + numbers[j] == target) { /* found */ }
    }
}

int left = 0;
int right = numbers.size() - 1;

while (left < right)
{
    int sum = numbers[left] + numbers[right];

    if (sum == target)
    {
        // found it
        break;
    }
    else if (sum < target)
    {
        left++; // sum too small — move left pointer up to increase it
    }
    else
    {
        right--; // sum too big — move right pointer down to decrease it
    }
}

#include <iostream>
#include <vector>

using namespace std;

int main()
{
    vector<int> numbers = {2, 4, 7, 11, 15};
    int target = 15;

    int left = 0;
    int right = numbers.size() - 1;

    while (left < right)
    {
        int sum = numbers[left] + numbers[right];

        if (sum == target)
        {
            cout << numbers[left] << " + " << numbers[right] << " = " << target << endl;
            break;
        }
        else if (sum < target)
        {
            left++;
        }
        else
        {
            right--;
        }
    }

    return 0;
}

